var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"일주일 뒤","JPN":"一週間後","ENG":"One week later","TWN":"一週後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"카나리아 스쿼드 선수 대기실, 건틀렛 리그 4강 <color=#ffd34c>3시간 전</color>","JPN":"カナリア・スクワッド選手待機室、ガントレットリーグ準決勝戦<color=#ffd34c>3時間前</color>","ENG":"Canary Squad waiting room, <color=#ffd34c>3 hours before</color> the Gauntlet League semifinals","TWN":"金絲雀小隊休息室，聖鎧聯賽4強賽<color=#ffd34c>開始前3小時</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐야, 카나리아 스쿼드는 어디있어?","JPN":"なんだ、カナリア・スクワッドはどこだ？","ENG":"Huh? Where's Canary Squad?","TWN":"喂，金絲雀小隊人呢？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"설마 또 늦을 생각은 아니겠지? 4강전 사전 인터뷰 있다고 연락 안 해뒀어?","JPN":"まさかまた遅れるんじゃないだろうな？　準決勝戦の前にインタビューがあるって連絡してなかったのか？","ENG":"They're not late again, are they? Didn't you tell them that they had an interview before the match?","TWN":"該不會又要給我遲到？沒人跟他們說4強賽開始前要先受訪嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"다시 연락해봐! 다른 방송보다 뒤쳐지면 안 된다고!","JPN":"もう一度連絡してみろ！　他の番組に遅れを取るわけにはいかないんだ！","ENG":"Call them again! We can't let the other stations interview them first!","TWN":"再去聯絡一下！不能輸給其他節目！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"나 참, 곤란하게 됐군.","JPN":"まったく、困ったものだ。","ENG":"Ugh... This isn't good.","TWN":"真是的，現在情況有點尷尬。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"지금부터 인터뷰를 시작해도 세 사람 분을 따려면 빠듯할 것 같은데.","JPN":"今すぐにインタビューを開始したとしても、3人分撮れるか微妙だぞ。","ENG":"Even if we start the interview now, it would be hard to do all three of them.","TWN":"就算現在開始採訪，三個都要訪問到的話時間會很緊。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"신생팀이 여기까지 올라온 게 얼마만인데, 이런 아이템을 다른 녀석들한테 뺏길 수도 없고.","JPN":"新人チームがここまで勝ち上がってくるなんていつぶりだ？　こんな特ダネを他の連中に取られるわけにはいかない。","ENG":"But it's been ages since a newly founded team managed to come this far. And I can't let a scoop like this go to my competitors!","TWN":"已經多久沒有新人隊伍晉級到前4強，這麼好的題材絕對不能被別人搶走！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"저 떠올랐어요! 감독님! 떠올랐다고요!","JPN":"私、浮かびました！　監督！　浮かんできましたよ！","ENG":"Oh, I got it, Sir! I got it!","TWN":"導演！有了！我想到了！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"뭐야, 갑자기 뭐가 떠올랐다는 거야?","JPN":"何だ、いきなり何が浮かんできたんだ？","ENG":"Huh? You got what?","TWN":"什麼啦，你想到什麼？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"네 개인 방송 시절 영상이 인기 급상승 영상으로 떠오르기라도 한 거야?","JPN":"君の配信者時代の動画が人気急上昇にでもなって浮かんできたのか？","ENG":"Did you get a late award for your early livestreaming days or something?","TWN":"你是想到你個人的直播影片點閱率激增嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아니! 그게 아니라! 물론, 그러면 더 좋겠지만!","JPN":"いいえ！　そうじゃなくて！　もちろん、それだったらもっといいんでしょうけど！","ENG":"No! That's not what I'm talking about! I mean, that would better, to be honest!","TWN":"不是啦！那樣當然也很好！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아무튼 카나리아 애들 인터뷰만 따면 되는 거죠?","JPN":"とにかくカナリアの子たちのインタビューができさえすればいいんですよね？","ENG":"Anyway, all you need is to get interviews with the Canary kids, right?","TWN":"但是，總之只要能採訪到金絲雀就OK吧？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그게 다른 경쟁 방송보다 빨리 라이브로 송출되기만 하면 되는 거고요?","JPN":"それが他の競合番組より早くライブ配信されればいいんですよね？","ENG":"On top of that, you want it to be streamed live faster than the other stations?","TWN":"只要搶先其他節目播出就OK吼？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTOR_NPC_NULL_NULL","text":{"KOREA":"어? 어어, 그렇지.","JPN":"え？　まぁ、そうだな。","ENG":"Huh? Y-yeah. That's right.","TWN":"蛤？嗯嗯，沒錯。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"저한테 방법이 있어요! 따라오세요!","JPN":"私にいい案があります！　ついてきてください！","ENG":"Then I got a plan! Follow me!","TWN":"那我有辦法！跟我來！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"좋아. 이 정도면 움직이는 데는 지장 없겠어.","JPN":"よし。これなら動くのに支障はなさそうだな。","ENG":"Okay. I don't think I'll have trouble moving around now.","TWN":"很好，現在身體動起來應該沒什麼障礙。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그런데 다들 왜 그렇게 몰골이 초췌해? 너무 긴장돼서 잠이라도 설친 거야?","JPN":"しかし、何でみんなそんなに顔色が悪いの？　緊張のしすぎてよく眠れなかった？","ENG":"But why do all of you look so tired? Did you not sleep well because you were too nervous about today?","TWN":"不過大家為何一臉憔悴？是太緊張沒睡好嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"후에에에엥……! 라이카 보고 싶었어요!","JPN":"ふえええええん……！　ライカ、会いたかったです！","ENG":"WAAAAH...! I missed you, Laika!","TWN":"嗚嗚嗚……！萊卡，我好想你喔！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐야, 얼빵이 너 왜 그래? 왜 울어?","JPN":"何だよ、どうした間抜け？　何で泣いているんだ？","ENG":"Huh? What's up with you, goon? Why are you crying?","TWN":"你幹嘛啊，小瓜呆？哭什麼哭啊？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐엉엉, 그동안 너무 힘들었어요. 너무나 많은 일이 있었다고요……!","JPN":"ふえーん、今まで本当に辛かったんです。色々なことがありすぎて……！","ENG":"Waah...! It's been really tough. So many things have happened...!","TWN":"嗚嗚嗚，你不在的時候發生好多事，心好累……！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"많은 일이라고? 무슨 일이 있었길래?","JPN":"色んなこと？　何があったんだ？","ENG":"What things? What even happened?","TWN":"發生很多事？是什麼事？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그게 그러니까…….","JPN":"それが、それが……","ENG":"Well...","TWN":"就是啊……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"매일 아침, 눈 뜨자마자 시작되는…… 무인 드론들의 무차별 폭격!","JPN":"毎朝、目覚めると同時に始まる……無人ドローンたちからの無差別爆撃！","ENG":"Every morning, I wake up to... THE RELENTLESS ATTACK OF DRONES!","TWN":"每天一睜開眼睛……就要面對無人機的無差別攻擊！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PECKER_SL_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다음은 자연스러운 만남을 위장한 미인계……!","JPN":"そして偶然の出会いを装ったハニートラップ……！","ENG":"Next comes the honey trap disguised as a coincidence...!","TWN":"接著是假裝巧遇的美人計……！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"안녕, 여기 슈트 핏이 잘 어울리고 돈도 잘 버는 사장님이 있다고 들었는데?","JPN":"こんにちは。ここにスーツのよく似合う、お金儲けも上手な社長がいると聞いたわ。","ENG":"Hey there. I heard there's a CEO around here who looks great in a suit and makes a lot of money. Do you know him?","TWN":"你好～我聽說有位很適合穿西裝，又很會賺錢的老闆。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"결혼을 전제로 얘기하고 싶은데 연락처 좀 받을 수 있을까?","JPN":"結婚を前提にお話がしたいのだけれど、連絡先を教えてもらってもいいかしら？","ENG":"I want to talk to him about marriage, so could I get his number, please?","TWN":"我想以結婚為前提跟他交往，你可以告訴我他的聯絡方式嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"또…… 독극물을 이용한 암살기도!","JPN":"それに……毒物を使っての暗殺未遂も！","ENG":"Also... There's the assassination attempt using poison!","TWN":"還有……下毒想殺你的！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"콜라~ 콜라~ 땀 흘렸을 때는 시원한 콜라를……","JPN":"コーラ～コーラ～汗をかいた後は涼しいコーラを……","ENG":"Coca! Cola! Nothing's better than a refreshing cup of coke–","TWN":"可樂～可樂～汗流的時候就是要來杯冰冰涼涼的可樂……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":" 꾸엑!?","JPN":" げっ！？","ENG":"AAAGH?!","TWN":"噁噁！？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_WATER_03"},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"누구야! 누가 냉장고에 콜라 대신 간장을!!","JPN":"誰！　冷蔵庫にコーラの代わりに醬油を入れたのは！！","ENG":"Who did this? Who put soy sauce instead of coke in the fridge?!","TWN":"是誰！誰把冰箱裡的可樂換成醬油的！！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"적어도 마지막 암살기도는 걔들 짓이 아닌 것 같은데?","JPN":"少なくとも最後の暗殺未遂はあいつらの仕業じゃないんじゃない？","ENG":"Well, I don't think that last one was an attempt from them.","TWN":"但下毒事件應該不是他們做的吧？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"크흠.","JPN":"ゴホン。","ENG":"Ahem.","TWN":"嗯哼。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아, 아무튼!","JPN":"と、とにかく！","ENG":"A-anyway!","TWN":"總，總之！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"라이카가 입원해 있는 동안, 코핀 컴퍼니 지사를 노린 습격이 무려…… 67번!","JPN":"ライカが入院している間、コフィンカンパニーの支社を狙った襲撃がなんと……67回！","ENG":"While you were hospitalized, Laika, there were 67 ambush attempts aimed at this Coffin Company branch!","TWN":"在萊卡住院的這段時間，衝著科芬分公司來的攻擊足足有……67次！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"S급 청소 요원님이랑 용병 언니가 도와주지 않았다면 아마 한숨도 못 잤을 거예요.","JPN":"S級の掃除エージェントさんと傭兵のお姉さんが助けてくれなかったら、たぶん一睡もできませんでしたよ。","ENG":"If the Grade S cleaning agent and that mercenary lady didn't help us out, then we wouldn't have been able to get an ounce of sleep.","TWN":"要不是有S級清潔特工和傭兵姊姊的幫忙，根本片刻不得安寧。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"육십…… 뭐? 용케 다들 살아있네?","JPN":"60……はあ？　よくみんな生きていられたな？","ENG":"Sixty-what? I'm surprised you're still alive.","TWN":"60……天啊？你們竟然還活著？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카는요? 라이카는 입원하고 있는 동안 별 일 없었어요?","JPN":"ライカは？　ライカは入院している間、何もありませんでしたか？","ENG":"What about you, Laika? Did anything happen to you while you were in the hospital?","TWN":"萊卡呢？你住院這段時間都還好嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 나도 죽을 뻔했어.","JPN":"いや、私も死ぬところだった。","ENG":"Hey, I almost died too.","TWN":"拜託，我也差點沒命欸。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"여기 환자식 더럽게 맛없더라고. 이것도 암살기도냐?","JPN":"ここの病院食はクソまずいんだ。これも暗殺未遂に入る？","ENG":"Almost died of starvation. Do you know how disgusting the food is here? Is that another assassination attempt on us?","TWN":"這裡的餐有夠難吃的，這該不會也是暗殺的手法之一吧？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"배부른 소리 하지 마. 사장님 아니었으면 여기 입원하지도 못했을 테니까.","JPN":"贅沢なこと言わないでよ。社長のおかげでやっと入院できたんだから。","ENG":"You shouldn't complain. If it weren't for Boss, you wouldn't have even been able to rest here in the first place.","TWN":"少在那邊得了便宜還賣乖，要不是老闆，你根本連住院的機會都沒有。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"뭐, 아무리 상대가 막장이라고 해도 상식적으로 중앙 병원까지 쳐들어오지는…….","JPN":"まぁ、いくらなんでもありな相手とはいっても、常識的に考えて中央病院まで攻め込んでくるなんてことは……","ENG":"Well, even if they're reckless, don't they still have the common sense not to invade the central hospital–","TWN":"沒那麼誇張啦，就算對方再怎麼凶狠，也不至於衝到醫院來……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"전 병동에 알립니다! 현재 신원 불명의 무장 단체들이 병동에 침입했습니다!","JPN":"全病棟に連絡！　現在身元不明の武装団体が病棟に侵入しています！","ENG":"Attention, all wards! An armed group of unidentified individuals has infiltrated the hospital!","TWN":"這裡是醫院的通知！目前有身分不明的武裝分子闖入醫院！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"전 직원은 중환자실부터 환자들의 대피를 최우선으로……!","JPN":"全職員は集中治療室の患者たちの避難を最優先に……！","ENG":"All personnel are to evacuate the patients in the ICU first...!","TWN":"請優先協助疏散加護病房的病人……！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"습격이에요! 이걸로 68번!","JPN":"襲撃です！　これでもう68回目！","ENG":"We're under attack! This is the 68th time!","TWN":"有攻擊！這是第68次！"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_SIREN_02"},{"id":"L34_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"하아, 미안. 내 상식이 부족했네.","JPN":"はぁ、ごめん。私の常識が足りなかったわ。","ENG":"*Sigh* Sorry. Guess I'm the one without common sense.","TWN":"哈，抱歉，我太小看他們了。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흐음. 여긴 라이카 양 말고 다른 환자들도 있을 텐데.","JPN":"ふむ。ここにはライカ君以外に他の患者たちもいるのにな。","ENG":"Hmm. But the hospital has other patients besides Laika.","TWN":"這裡除了萊卡之外還有其他的病人，"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지저분한 방식은 예전에 방문했을 때와 별반 차이가 없군.","JPN":"汚いやり方は昔から変わっていないようだな。","ENG":"Their dirty tricks are no different from when we visited here last time.","TWN":"手段都沒進步，和當時我拜訪時一樣粗糙。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 경쟁자 없는 시장은 발전하지 못하는 건가.","JPN":"やはり競争のない市場は発展しないということか。","ENG":"Perhaps this is why markets without competition can never improve.","TWN":"果然市場上沒有競爭對手就不會進步嗎？"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐 어때. 하루 이틀도 아니고. 받은 만큼 갚아주면 그만이잖아?","JPN":"まぁいいよ。いつものことだし、やられた分、やり返せばいいだけだろ？","ENG":"Well, who cares? It's not the first time they've done this. Plus, we just have to get them back punch for punch, no?","TWN":"管他的，也不是一天二天的事，反正就是以牙還牙，以眼還眼！"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나 참. 평생 생일 축하도 받은 적 없는데, 퇴원 축하를 이런 식으로 받게 될 줄이야.","JPN":"全く。生まれてこのかた誕生祝いもされたことないのに、こんな退院祝いをされるなんてな。","ENG":"Ugh. I've never been congratulated on my birthday, but here I am, being congratulated for getting discharged.","TWN":"真是的，我連生日都沒人替我慶祝過，現在要出院卻用這種方式替我慶祝。"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"경기 시작 전 간단한 워밍업 정도로는 괜찮으려나?","JPN":"試合前の軽いウォーミングアップとしてなら悪くないのか？","ENG":"Well, I guess this can be a warm-up before the main match.","TWN":"就當作是賽前暖暖身吧？"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"가자, 꼬맹이. 오랜만에 호흡이나 맞춰보자고!","JPN":"よし、行くぜおこちゃま。久しぶりに連携の練習だ！","ENG":"Let's go, kiddo. It's time to see if our teamwork is still good as ever!","TWN":"走吧，小鬼。好久沒一起出手囉？"},"stage":{"bg":"HOSPITAL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};